+#[inline]
 pub fn record_snapshot_read_versions_traversed(versions_traversed: u64) {
+    if !MVCC_SNAPSHOT_METRICS_ENABLED.load(Ordering::Relaxed) {
+        return;
+    }
+    record_snapshot_read_versions_traversed_slow(versions_traversed);
+}
